sys_push_notif_msg_content.script:
(function buildJSON(/*GlideRecord*/ current, /*String*/ message, /*Object*/ attributes) {

	var json = {};

	var layoutFieldGenerator = new global.NotificationLayoutFieldGenerator();
	var identifier = layoutFieldGenerator.layoutField(current.sys_class_name, current.sys_id, "short_description");
	var description = layoutFieldGenerator.layoutField(current.sys_class_name, current.sys_id, "u_objective");
	var status = layoutFieldGenerator.layoutField(current.sys_class_name, current.sys_id, "state");

	var deepLinkGenerator = new global.MobileDeepLinkGenerator("request");
	// going to View Tasks Assigned to Me list applet
	var link = deepLinkGenerator.getFormScreenLink("6b2a4f28dbb49410dd0cdbdb5e961939", current.getTableName(), current.getValue("sys_id"));

	// build JSON sent by push here
	json = {
		"aps" : {
			"sound" : "default"
		},
		"Link": link,
		"Layout" : {
			"Status": status,
			"Identifier" : identifier,
			"Description" : description
		}
	};

	return json;

})(current, message, attributes);
